+    // ── Contention metrics ────────────────────────────────────────
+    render_contention_metrics(&mut out, &result.perf);
+
+    // ── Error summary ─────────────────────────────────────────────
+    let errors: Vec<_> = result
+        .perf
+        .cells
+        .iter()
+        .filter(|c| c.error.is_some())
+        .collect();
+    if !errors.is_empty() {
+        let _ = writeln!(out, "## Errors\n");
+        for cell in &errors {
+            let _ = writeln!(
+                out,
+                "- **{}** / {} / c{}: {}",
+                cell.engine,
+                cell.workload,
+                cell.concurrency,
+                cell.error.as_deref().unwrap_or("unknown"),
+            );
+        }
+        let _ = writeln!(out);
+    }
+
+    out
+}
